import { useMemo } from "react";
import { useInfiniteQuery } from "@tanstack/react-query";
import { apiFetch } from "@/utils/api";

function buildQuery(params, cursor) {
  const p = new URLSearchParams();

  if (params?.search) p.set("search", params.search);
  if (params?.status) p.set("status", params.status);
  if (params?.assignedToUserId)
    p.set("assignedToUserId", params.assignedToUserId);
  if (params?.territoryId != null)
    p.set("territoryId", String(params.territoryId));
  if (params?.dateField) p.set("dateField", params.dateField);
  if (params?.dateFrom) p.set("dateFrom", params.dateFrom);
  if (params?.dateTo) p.set("dateTo", params.dateTo);

  p.set("limit", String(params?.limit || 50));
  if (cursor) p.set("cursor", cursor);

  return p.toString();
}

function dedupeById(rows) {
  const out = [];
  const seen = new Set();
  for (const r of rows) {
    const id = r?.id;
    const key = id == null ? null : String(id);
    if (!key) continue;
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(r);
  }
  return out;
}

export default function useCustomersList({
  search,
  status,
  assignedToUserId,
  territoryId,
  dateField,
  dateFrom,
  dateTo,
  limit = 50,
}) {
  const safeTerritoryId = useMemo(() => {
    if (territoryId == null) return null;
    const n = Number(territoryId);
    return Number.isFinite(n) ? Math.trunc(n) : null;
  }, [territoryId]);

  const query = useInfiniteQuery({
    queryKey: [
      "customers",
      search || "",
      status || "",
      assignedToUserId || "",
      safeTerritoryId || "",
      dateField || "",
      dateFrom || "",
      dateTo || "",
      String(limit),
    ],
    queryFn: async ({ pageParam }) => {
      const queryString = buildQuery(
        {
          search,
          status,
          assignedToUserId,
          territoryId: safeTerritoryId,
          dateField,
          dateFrom,
          dateTo,
          limit,
        },
        pageParam,
      );

      const res = await apiFetch(`/api/customers?${queryString}`, {
        method: "GET",
      });

      const json = await res.json().catch(() => ({}));
      if (!res.ok) {
        throw new Error(json?.error || `Customers load failed (${res.status})`);
      }

      const items = Array.isArray(json?.items) ? json.items : [];
      const nextCursor =
        typeof json?.nextCursor === "string" ? json.nextCursor : null;

      return { items, nextCursor };
    },
    getNextPageParam: (lastPage) => {
      return lastPage?.nextCursor || undefined;
    },
    initialPageParam: undefined,
    retry: 1,
    staleTime: 30_000,
    gcTime: 5 * 60_000,
  });

  const items = useMemo(() => {
    const pages = Array.isArray(query.data?.pages) ? query.data.pages : [];
    const rows = pages.flatMap((p) => (Array.isArray(p?.items) ? p.items : []));
    return dedupeById(rows);
  }, [query.data?.pages]);

  return { query, items };
}

